package org.jsoup.parser;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.parser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.select.Elements;
import static org.junit.Assert.*;

public class StepDefs {
    private String htmlInput;
    private Document document;

    @Given("the HTML input:")
    public void the_html_input(String html) {
        this.htmlInput = html;
    }

    @When("the document is parsed")
    public void the_document_is_parsed() {
        // Using jsoup to parse the HTML
        try {
            this.document = Jsoup.parse(htmlInput);
        } catch (Exception e) {
            fail("Exception during parsing: " + e.getMessage());
        }
    }

    @Then("the {string} element should have a child {string}")
    public void element_should_have_child(String parentTag, String childTag) {
        Elements parentElements = document.select(parentTag);
        assertFalse("Parent element " + parentTag + " should exist", parentElements.isEmpty());
        Element parentElement = parentElements.first();

        Elements children = parentElement.children();
        boolean hasChild = false;
        for (Element child : children) {
            if (child.tagName().equalsIgnoreCase(childTag)) {
                hasChild = true;
                break;
            }
        }
        assertTrue("Parent element " + parentTag + " should have a child " + childTag, hasChild);
    }

    @Then("the {string} element inside {string} should have a child {string}")
    public void template_inside_element_should_have_child(String innerChildTag, String parentTag, String grandChildTag) {
        Elements parentElements = document.select(parentTag);
        assertFalse("Parent element " + parentTag + " should exist", parentElements.isEmpty());
        Element parentElement = parentElements.first();

        Elements innerElements = parentElement.select(innerChildTag);
        assertFalse("Child element " + innerChildTag + " should exist inside " + parentTag, innerElements.isEmpty());
        Element innerElement = innerElements.first();

        Elements children = innerElement.children();
        boolean hasChild = false;
        for (Element child : children) {
            if (child.tagName().equalsIgnoreCase(grandChildTag)) {
                hasChild = true;
                break;
            }
        }
        assertTrue("Element " + innerChildTag + " inside " + parentTag + " should have a child " + grandChildTag, hasChild);
    }

    @Then("the {string} elements should remain inside the table structure")
    public void template_elements_should_remain_inside_table(String elementTag) {
        Elements templateElements = document.select(elementTag);
        assertEquals("There should be 2 template elements", 2, templateElements.size());

        Elements theadTemplates = document.select("thead > " + elementTag);
        assertFalse("Template element should be inside thead", theadTemplates.isEmpty());

        Elements tbodyTemplates = document.select("tbody > " + elementTag);
        assertFalse("Template element should be inside tbody", tbodyTemplates.isEmpty());
    }
}

