                          "      <tr><td>Cell</td></tr>\n" +
                          "    </template>\n" +
                          "  </tbody>\n" +
                          "</table>";

            System.out.println("Parsing HTML with template tags in table structures...");
            Document doc = Jsoup.parse(html);

            System.out.println("Parsed document:");
            System.out.println(doc.html());

            // Check the requirements from the feature file
            // 1. the "thead" element should have a child "template"
            Element thead = doc.selectFirst("thead");
            if (thead != null) {
                Elements theadChildren = thead.children();
                boolean hasTemplate = false;
                for (Element child : theadChildren) {
                    if (child.tagName().equalsIgnoreCase("template")) {
                        hasTemplate = true;
                        break;
                    }
                }
                System.out.println("✓ thead has template child: " + hasTemplate);

                if (hasTemplate) {
                    Element templateInTHead = thead.selectFirst("template");
                    Elements templateChildren = templateInTHead.children();
                    boolean hasTh = false;
                    for (Element child : templateChildren) {
                        if (child.tagName().equalsIgnoreCase("th")) {
                            hasTh = true;
                            break;
                        }
                    }
                    System.out.println("✓ template inside thead has th child: " + hasTh);
                }
            }

            // 2. the "template" element inside "thead" should have a child "th"
            // (Already checked above)

            // 3. the "tbody" element should have a child "template"
            Element tbody = doc.selectFirst("tbody");
            if (tbody != null) {
                Elements tbodyChildren = tbody.children();
                boolean hasTemplate = false;
                for (Element child : tbodyChildren) {
                    if (child.tagName().equalsIgnoreCase("template")) {
                        hasTemplate = true;
                        break;
                    }
                }
                System.out.println("✓ tbody has template child: " + hasTemplate);

                if (hasTemplate) {
                    Element templateInTBody = tbody.selectFirst("template");
                    Elements templateChildren = templateInTBody.children();
